/* Slice-by-4 tables for unreflected CRC32 (polynomial 0x04C11DB7).
   T1[i] = T0[i] advanced by 1 zero byte, T2 by 2, T3 by 3.
   Formula: crc' = T3[(crc>>24)^b0] ^ T2[((crc>>16)&0xFF)^b1]
                 ^ T1[((crc>>8)&0xFF)^b2] ^ T0[(crc&0xFF)^b3]  */

